const topics = $json.topics;
const topic = topics[Math.floor(Math.random() * topics.length)];
const date = new Date().toISOString().split('T')[0];
const slug = topic.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'') + '-' + date;
return [{ json: { topic, slug, date } }];

const body = $input.item.json;
const slug = $('Pick Topic').item.json.slug;
const topic = $('Pick Topic').item.json.topic;
const date = $('Pick Topic').item.json.date;

const articleText = body.choices?.[0]?.message?.content || '';

let title = topic.charAt(0).toUpperCase() + topic.slice(1);
let bodyText = articleText;
const firstLine = articleText.split('\n')[0];
if (firstLine.startsWith('# ')) {
  title = firstLine.slice(2).trim();
  bodyText = articleText.split('\n').slice(1).join('\n').trim();
}

// Capitalize title properly
title = title.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

const description = bodyText.replace(/^#+.*$/gm, '').replace(/\n+/g, ' ').trim().slice(0, 160);

const tags = topic.toLowerCase().split(' ').filter(w => w.length > 3).slice(0, 6)
  .map(w => w.replace(/[^a-z0-9]/g, ''));

const heroSlug = slug.replace(/\d{4}-\d{2}-\d{2}$/, '').replace(/-$/, '');

const frontmatter = `---
title: "${title.replace(/"/g, "'")}"
description: "${description.replace(/"/g, "'")}"
publishDate: "${date}"
tags: [${tags.map(t => `"${t}"`).join(', ')}]
heroImage: "/images/${heroSlug}.jpg"
---`;

const fullContent = frontmatter + '\n\n' + bodyText;

return [{ json: { fullContent, title, slug } }];

